        material_balance = 0
        for row in self.board:
            for piece in row:
                if piece.isupper():
                    material_balance += self.piece_values.get(piece, 0)
                elif piece.islower():
                    material_balance -= self.piece_values.get(piece.upper(), 0)
        return material_balance

