        elif board.is_attacked_by(chess.BLACK, square):
            black_controlled_squares += 1

    # Evaluate active moves
    for move in board.legal_moves:
        if move.from_square in board.piece_map() and board.piece_at(move.from_square).color == chess.WHITE:
            white_active_moves += 1
        elif move.from_square in board.piece_map() and board.piece_at(move.from_square).color == chess.BLACK:
