import chess

def evaluate_position(board):
    # Initialize evaluation metrics
    white_material = 0
    black_material = 0
    white_controlled_squares = 0
    black_controlled_squares = 0
    white_active_moves = 0
    black_active_moves = 0
    check_possibilities = 0
    mate_possibilities = 0

    # Evaluate material
    for piece in board.piece_map().values():
        if piece.color == chess.WHITE:
            if piece.piece_type == chess.PAWN:
                white_material += 1
            elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                white_material += 3
            elif piece.piece_type == chess.ROOK:
                white_material += 5
            elif piece.piece_type == chess.QUEEN:
                white_material += 9
        elif piece.color == chess.BLACK:
            if piece.piece_type == chess.PAWN:
                black_material += 1
            elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                black_material += 3
            elif piece.piece_type == chess.ROOK:
                black_material += 5
            elif piece.piece_type == chess.QUEEN:
                black_material += 9

    # Evaluate controlled squares
    for square in chess.SQUARES:
        if board.is_attacked_by(chess.WHITE, square):
            white_controlled_squares += 1
        elif board.is_attacked_by(chess.BLACK, square):
            black_controlled_squares += 1

    # Evaluate active moves
    for move in board.legal_moves:
        if move.from_square in board.piece_map() and board.piece_at(move.from_square).color == chess.WHITE:
            white_active_moves += 1
        elif move.from_square in board.piece_map() and board.piece_at(move.from_square).color == chess.BLACK:
            black_active_moves += 1

    # Evaluate check and mate possibilities
    if board.is_check():
        if board.is_checkmate():
            mate_possibilities += 1
        else:
            check_possibilities += 1

    # Calculate evaluation
    evaluation = white_material - black_material + (white_controlled_squares - black_controlled_squares) / 10 + (white_active_moves - black_active_moves) / 10 + check_possibilities - mate_possibilities

    return evaluation

