import chess

def evaluate_position(position):
    board = chess.Board(position)
    evaluation = 0
    piece_values = {'P': 1, 'N': 3, 'B': 3, 'R': 5, 'Q': 9}

    for piece in board.piece_map().values():
        if piece.color == chess.WHITE:
            evaluation += piece_values[piece.symbol().upper()]
        else:
            evaluation -= piece_values[piece.symbol().upper()]

    controlled_squares = 0
    for square in chess.SQUARES:
        if board.is_attacked_by(chess.WHITE, square):
            controlled_squares += 1
        elif board.is_attacked_by(chess.BLACK, square):
            controlled_squares -= 1

    active_moves = 0
    for move in board.legal_moves:
        active_moves += 1

    check_possibilities = 0
    if board.is_check():
        check_possibilities += 1

    mate_possibilities = 0
    if board.is_checkmate():
        mate_possibilities += 1

    evaluation += controlled_squares / 10
    evaluation += active_moves / 100
    evaluation += check_possibilities * 10
    evaluation += mate_possibilities * 100

    if evaluation > 0:
        return f"White has an advantage of {evaluation:.2f}"
    elif evaluation < 0:
        return f"Black has an advantage of {-evaluation:.2f}"
    else:
        return "The position is equal"

def main():
    position = input("Enter a chess position in FEN format: ")
    print(evaluate_position(position))

if __name__ == "__main__":
    main()

