class DominationFalknerSkan:
    def __init__(self, alpha, beta, gamma, delta):
        self.alpha = alpha
        self.beta = beta
        self.gamma = gamma
        self.delta = delta

    def falkner_skan_velocity(self, eta):
        return (self.alpha * eta + self.beta) * (self.gamma * eta + self.delta)

    def acceleration(self, eta):
        return self.alpha * self.gamma * eta**2 + (self.alpha * self.delta + self.beta * self.gamma) * eta + self.beta * self.delta

    def get_domination(self, eta):
        return self.falkner_skan_velocity(eta) / self.acceleration(eta)

class PermutationGroup:
    def __init__(self, elements):
        self.elements = elements

    def get_permutations(self):
        if len(self.elements) == 1:
            return [self.elements]
        permutations = []
        for i in range(len(self.elements)):
            element = self.elements[i]
            remaining_elements = self.elements[:i] + self.elements[i+1:]
            for p in PermutationGroup(remaining_elements).get_permutations():
