    def __init__(self):
        self.notes = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B']
        self.intervals = {
            'perfect unison': 0,
            'minor second': 1,
            'major second': 2,
            'minor third': 3,
            'major third': 4,
            'perfect fourth': 5,
            'tritone': 6,
            'perfect fifth': 7,
            'minor sixth': 8,
            'major sixth': 9,
            'minor seventh': 10,
            'major seventh': 11,
            'perfect octave': 12
        }
        self.chords = {
            'major': [0, 4, 7],
            'minor': [0, 3, 7],
            'diminished': [0, 3, 6],
            'augmented': [0, 4, 8]
        }

    def get_note(self, note_name):
        return self.notes.index(note_name)

    def get_interval(self, interval_name):
        return self.intervals[interval_name]

    def get_chord(self, chord_name):
        return self.chords[chord_name]

    def calculate_scale(self, root_note, scale_type):
        if scale_type == 'major':
            scale_intervals = [0, 2, 4, 5, 7, 9, 11]
        elif scale_type == 'minor':
            scale_intervals = [0, 2, 3, 5, 7, 8, 10]
        else:
            raise ValueError('Invalid scale type')
        root_index = self.get_note(root_note)
        scale = [(root_index + interval) % 12 for interval in scale_intervals]
        return [self.notes[i] for i in scale]

    def calculate_chord_progression(self, chords):
        progression = []
        for chord in chords:
            root_note, chord_type = chord.split()
            root_index = self.get_note(root_note)
            chord_intervals = self.get_chord(chord_type)
            chord_notes = [(root_index + interval) % 12 for interval in chord_intervals]
            progression.append([self.notes[i] for i in chord_notes])
        return progression

