def calculate_score(word):
    scores = {'a': 1, 'e': 1, 'i': 1, 'o': 1, 'u': 1, 'l': 1, 'n': 1, 'r': 1, 's': 1, 't': 1,
              'd': 2, 'g': 2, 'b': 3, 'c': 3, 'm': 3, 'p': 3, 'f': 4, 'h': 4, 'v': 4, 'w': 4, 'y': 4,
              'k': 5, 'j': 8, 'x': 8, 'q': 10, 'z': 10}
    return sum(scores.get(char.lower(), 0) for char in word)

def calculate_word_value(word):
    score = calculate_score(word)
    if len(word) > 2:
        for i in range(len(word) - 2):
            for j in range(i + 1, len(word) - 1):
                for k in range(j + 1, len(word)):
                    substring = word[i] + word[j] + word[k]
                    if calculate_score(substring) > score:
                        score = calculate_score(substring)
    return score

def calculate_sentence_value(sentence):
    words = sentence.split()
    total_value = 0
    for word in words:
        word = ''.join(e for e in word if e.isalnum())
        total_value += calculate_word_value(word)
    return total_value

def calculate_text_value(text):
    sentences = text.split('. ')
    total_value = 0
    for sentence in sentences:
        total_value += calculate_sentence_value(sentence)
    return total_value

