def to_roman(num):
    val = [
        1000, 900, 500, 400,
        100, 90, 50, 40,
        10, 9, 5, 4,
        1
        ]
    syb = [
        "M", "CM", "D", "CD",
        "C", "XC", "L", "XL",
        "X", "IX", "V", "IV",
        "I"
        ]
    roman_num = ''
    i = 0
    while  num > 0:
        for _ in range(num // val[i]):
            roman_num += syb[i]
            num -= val[i]
        i += 1
    return roman_num

def from_roman(roman_num):
    roman_num = roman_num.upper()
    mapping = {
        'M': 1000, 'D': 500, 'C': 100, 'L': 50, 'X': 10, 'V': 5, 'I': 1
    }
    integer = 0
    i = 0
    while i < len(roman_num):
        if i+1 < len(roman_num) and mapping[roman_num[i]] < mapping[roman_num[i+1]]:
            integer += mapping[roman_num[i+1]] - mapping[roman_num[i]]
            i += 2
        else:
            integer += mapping[roman_num[i]]
            i += 1
    return integer

def main():
    test_cases = [1, 4, 5, 9, 13, 44, 1000]
    for test_case in test_cases:
        roman = to_roman(test_case)
        print(f"Integer: {test_case}, Roman: {roman}, Back to Integer: {from_roman(roman)}")

if __name__ == "__main__":
    main()

