class Encryption:
    def __init__(self, key):
        self.key = key

    def encrypt(self, text):
        encrypted_text = ""
        for char in text:
            if char.isalpha():
                ascii_offset = 65 if char.isupper() else 97
                encrypted_char = chr((ord(char) - ascii_offset + self.key) % 26 + ascii_offset)
                encrypted_text += encrypted_char
            else:
                encrypted_text += char
        return encrypted_text

def create_caesar_cipher(key):
    return Encryption(key)

